INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (150001,'Legal Memorandum: Analysis of Exhibits in State v. Cameron Doyle Church','This document is a legal memorandum dated October 26, 2023, analyzing exhibits related to the criminal proceedings against Cameron Doyle Church in Washoe County, Nevada, Case No. CR23-0657. It details charges of Grand Larceny and Unlawful Taking of a Motor Vehicle, tracking the case from initial arrest and OR release through bindover to District Court, amended complaints, and eventual revocation of OR due to non-compliance. The memorandum highlights procedural irregularities, specifically persistent clerical errors in court documents regarding the District Court case number, and notes a curious eviction motion from a third party alleging harassment and deputy involvement.','evidence/ingest-180001-2023_all_of_it_Combined_with_Index_5cb625f8.pdf','/manus-storage/evidence/ingest-180001-2023_all_of_it_Combined_with_Index_5cb625f8.pdf','application/pdf',8916845,'other','CR23-0657','2023-10-26 00:00:00','Cameron Doyle Church, Richard Warren Joyce, Marie, Senior Partner, Legal Analyst, Washoe County District Attorney\'s Office, Reno Justice Court, Second Judicial District Court, Pretrial Services','[\"state-case\", \"custody\", \"motion\", \"warrant\", \"competency\", \"due-process\", \"prosecutorial-conduct\", \"judicial-nonfeasance\", \"pretrial-detention\", \"records-gap\", \"repeat-actor\", \"complaint\", \"hearing\", \"order\"]',NULL,0,'rejected','unverified',1,'This document is a legal memorandum dated October 26, 2023, analyzing exhibits related to the criminal proceedings against Cameron Doyle Church in Washoe County, Nevada, Case No. CR23-0657. It details charges of Grand Larceny and Unlawful Taking of a Motor Vehicle, tracking the case from initial arrest and OR release through bindover to District Court, amended complaints, and eventual revocation of OR due to non-compliance. The memorandum highlights procedural irregularities, specifically persistent clerical errors in court documents regarding the District Court case number, and notes a curious eviction motion from a third party alleging harassment and deputy involvement.','[\"state-case\", \"custody\", \"motion\", \"warrant\", \"competency\", \"due-process\", \"prosecutorial-conduct\", \"judicial-nonfeasance\", \"pretrial-detention\", \"records-gap\", \"repeat-actor\", \"complaint\", \"hearing\", \"order\"]','2026-05-18 12:50:39','2026-05-19 10:23:56','pending_review','no_ai_processing',NULL,NULL,'FILE NEEDS RE-UPLOAD: original S3 key had spaces (CloudFront 403). Re-ingest the original PDF to restore.',NULL,'state');
INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (150002,'Legal Memorandum: Analysis of State of Nevada vs. Cameron Doyle Church (CR23-0657) Exhibits','This document is a legal memorandum analyzing exhibits related to the criminal case State of Nevada vs. Cameron Doyle Church (CR23-0657). It details a contentious case involving allegations of constitutional violations, a breakdown in attorney-client relationships, and the court\'s striking of the defendant\'s pro se filings. The memorandum indicates a pattern of judicial resistance to the defendant\'s self-representation efforts and serious allegations of misconduct against multiple actors.','evidence/ingest-180002-2024_state_all_of_Combined_with_Index_daa1d1fb.pdf','/manus-storage/evidence/ingest-180002-2024_state_all_of_Combined_with_Index_daa1d1fb.pdf','application/pdf',14776363,'other','CR23-0657','2024-12-24 00:00:00','Cameron Doyle Church, Cooper Brinson, Sydney Hutt, Biray Dogan, Marie Engelhorn, Mary Kandaras','[\"prosecutorial-conduct\", \"judicial-nonfeasance\", \"ignored-motion\", \"faretta\", \"self-representation\", \"competency\", \"speedy-trial\", \"ineffective-assistance-of-counsel\", \"due-process\", \"complaint\", \"writ-of-mandamus\", \"conflict-counsel\", \"repeat-actor\"]',NULL,0,'pending','unverified',1,'This document is a legal memorandum analyzing exhibits related to the criminal case State of Nevada vs. Cameron Doyle Church (CR23-0657). It details a contentious case involving allegations of constitutional violations, a breakdown in attorney-client relationships, and the court\'s striking of the defendant\'s pro se filings. The memorandum indicates a pattern of judicial resistance to the defendant\'s self-representation efforts and serious allegations of misconduct against multiple actors.','[\"prosecutorial-conduct\", \"judicial-nonfeasance\", \"ignored-motion\", \"faretta\", \"self-representation\", \"competency\", \"speedy-trial\", \"ineffective-assistance-of-counsel\", \"due-process\", \"complaint\", \"writ-of-mandamus\", \"conflict-counsel\", \"repeat-actor\"]','2026-05-18 12:51:24','2026-05-18 16:58:18','pending_review','no_ai_processing',NULL,NULL,'FILE NEEDS RE-UPLOAD: original S3 key had spaces (CloudFront 403). Re-ingest the original PDF to restore.',NULL,'state');
INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (180001,'Legal Memorandum Analyzing Exhibits in State v. Church (CR23-0657)','This document is a legal memorandum dated October 26, 2023, analyzing exhibits related to the criminal proceedings against Cameron Doyle Church in Washoe County, Nevada, Case No. CR23-0657. It details charges of Grand Larceny and Unlawful Taking of a Motor Vehicle, tracking the case from arrest through bindover to District Court and subsequent pretrial release issues. The memorandum highlights a clerical error in the District Court case number on supervised release documents and notes an unusual eviction motion from a third party, Marie, alleging harassment by \'Cameron\' and deputy involvement, raising questions about potential bias or misuse of law enforcement resources. The analysis identifies procedural flags related to the case number error and the implications of the eviction motion.','evidence/ingest-210001-2023_all_of_it_Combined_with_Index_edf9ba37.pdf','/manus-storage/evidence/ingest-210001-2023_all_of_it_Combined_with_Index_edf9ba37.pdf','application/pdf',8916845,'other','CR23-0657','2023-10-26 00:00:00','Cameron Doyle Church, Richard Warren Joyce, Marie, Senior Partner, Legal Analyst, District Attorney\'s office, Reno Justice Court, Second Judicial District Court, Pretrial Services','[\"state-case\", \"grand-larceny\", \"unlawful-taking\", \"pretrial-release\", \"clerical-error\", \"due-process\", \"prosecutorial-conduct\", \"judicial-nonfeasance\", \"records-gap\", \"complaint\", \"motion\", \"hearing\", \"order\"]',60001,1,'approved','unverified',1,'This document is a legal memorandum dated October 26, 2023, analyzing exhibits related to the criminal proceedings against Cameron Doyle Church in Washoe County, Nevada, Case No. CR23-0657. It details charges of Grand Larceny and Unlawful Taking of a Motor Vehicle, tracking the case from arrest through bindover to District Court and subsequent pretrial release issues. The memorandum highlights a clerical error in the District Court case number on supervised release documents and notes an unusual eviction motion from a third party, Marie, alleging harassment by \'Cameron\' and deputy involvement, raising questions about potential bias or misuse of law enforcement resources. The analysis identifies procedural flags related to the case number error and the implications of the eviction motion.','[\"state-case\", \"grand-larceny\", \"unlawful-taking\", \"pretrial-release\", \"clerical-error\", \"due-process\", \"prosecutorial-conduct\", \"judicial-nonfeasance\", \"records-gap\", \"complaint\", \"motion\", \"hearing\", \"order\"]','2026-05-19 10:18:45','2026-05-19 10:18:46','public_preview','no_ai_processing',NULL,NULL,NULL,NULL,'state');
INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (180002,'Exhibit Index and Legal Memorandum: State of Nevada v. Cameron Doyle Church (CR23-0657)','This document is an exhibit index and legal memorandum analyzing the case of State of Nevada v. Cameron Doyle Church, case number CR23-0657. It details a contentious criminal case spanning September 2023 to December 2024, marked by a breakdown in the attorney-client relationship, multiple *Young v. State* hearings, and the appointment of conflict counsel. The defendant, Cameron Doyle Church, has repeatedly attempted to file *pro se* motions alleging systemic constitutional violations, including speedy trial infringements, ineffective assistance of counsel, prosecutorial misconduct, and judicial bias. The court has consistently struck these *pro se* filings, leading to a competency evaluation, a bench warrant, and the defendant\'s filing of a *pro se* Writ of Mandamus.','evidence/ingest-210002-2024_state_all_of_Combined_with_Index_606c35a0.pdf','/manus-storage/evidence/ingest-210002-2024_state_all_of_Combined_with_Index_606c35a0.pdf','application/pdf',14776363,'other','CR23-0657','2024-12-24 00:00:00','Cameron Doyle Church, Cooper Brinson, Sydney Hutt, Biray Dogan, Marie Engelhorn, Mary Kandaras, Aziz','[\"speedy-trial\", \"faretta\", \"self-representation\", \"competency\", \"no-bail-warrant\", \"ignored-motion\", \"public-defender\", \"prosecutorial-conduct\", \"judicial-nonfeasance\", \"pretrial-detention\", \"due-process\", \"complaint\", \"grievance\", \"hearing\", \"order\", \"transcript\", \"custody-pressure\", \"repeat-actor\"]',60001,1,'approved','unverified',1,'This document is an exhibit index and legal memorandum analyzing the case of State of Nevada v. Cameron Doyle Church, case number CR23-0657. It details a contentious criminal case spanning September 2023 to December 2024, marked by a breakdown in the attorney-client relationship, multiple *Young v. State* hearings, and the appointment of conflict counsel. The defendant, Cameron Doyle Church, has repeatedly attempted to file *pro se* motions alleging systemic constitutional violations, including speedy trial infringements, ineffective assistance of counsel, prosecutorial misconduct, and judicial bias. The court has consistently struck these *pro se* filings, leading to a competency evaluation, a bench warrant, and the defendant\'s filing of a *pro se* Writ of Mandamus.','[\"speedy-trial\", \"faretta\", \"self-representation\", \"competency\", \"no-bail-warrant\", \"ignored-motion\", \"public-defender\", \"prosecutorial-conduct\", \"judicial-nonfeasance\", \"pretrial-detention\", \"due-process\", \"complaint\", \"grievance\", \"hearing\", \"order\", \"transcript\", \"custody-pressure\", \"repeat-actor\"]','2026-05-19 10:20:01','2026-05-19 10:22:35','public_preview','no_ai_processing',NULL,NULL,NULL,NULL,'state');
INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (210001,'December 5, 2024 Young/Faretta/Competency Hearing Transcript','Full transcript of the December 5, 2024 hearing in which Judge Breslow conducted a Young hearing, addressed Faretta self-representation, and initiated competency proceedings. Contains the now-documented exchange: \"Witness? I don\'t even know what that means.\"','Dec5thTranscript_6e438917.pdf','/manus-storage/Dec5thTranscript_6e438917.pdf','application/pdf',66434,'transcript','CR23-0657','2024-12-05 00:00:00','Judge Barry Breslow, Aziz Merchant, Galen Carrico, Cameron Church','[\"faretta\", \"young_hearing\", \"competency\", \"self_representation\"]',1,1,'approved','verified',1,NULL,NULL,'2026-05-20 23:27:37','2026-05-20 23:27:37','pending_review','no_ai_processing',NULL,NULL,NULL,NULL,'state');
INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (210002,'February 21, 2025 — Call with US Marshal Supervisor (Standoff Aftermath)','Recorded call between Cameron Church and US Marshal Supervisor Darrell Halbeck following the February 11, 2025 law enforcement standoff at Church\'s residence. Halbeck confirms no arrest was made. Church raises gang-stalking concerns and questions the warrant basis.','02-21-25callwillusmarshals_8d9216c6.pdf','/manus-storage/02-21-25callwillusmarshals_8d9216c6.pdf','application/pdf',72227,'audio','CR23-0657','2025-02-21 00:00:00','Cameron Church, Darrell Halbeck (US Marshal Supervisor)','[\"warrant\", \"no_bail\", \"law_enforcement\", \"standoff\"]',1,1,'approved','verified',1,NULL,NULL,'2026-05-20 23:27:37','2026-05-20 23:27:37','pending_review','no_ai_processing',NULL,NULL,NULL,NULL,'state');
