INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (270001,'Email: \'Your Circus of Retaliation: A Brief Retrospective\'','This document is an email sent by Cameron Church to Deputy District Attorney Aziz Merchant on January 19, 2025. The email alleges prosecutorial misconduct, including retaliation and collusion, in the context of competency evaluations and procedural tactics. It directly references Aziz Merchant\'s actions and mentions \'Galen\' in connection with court procedures.','evidence/ingest-240001-01-19-25_-_Your_Circus_of_Retaliation_A_Brief_Retrospective_eafc8b4f.pdf','/manus-storage/evidence/ingest-240001-01-19-25_-_Your_Circus_of_Retaliation_A_Brief_Retrospective_eafc8b4f.pdf','application/pdf',135539,'email',NULL,'2025-01-19 00:00:00','Cameron Church, Aziz Merchant, Galen Carrico','[\"prosecutorial-conduct\", \"retaliation\", \"competency\", \"due-process\", \"communications\", \"repeat-actor\"]',60001,1,'approved','unverified',1,'This document is an email sent by Cameron Church to Deputy District Attorney Aziz Merchant on January 19, 2025. The email alleges prosecutorial misconduct, including retaliation and collusion, in the context of competency evaluations and procedural tactics. It directly references Aziz Merchant\'s actions and mentions \'Galen\' in connection with court procedures.','[\"prosecutorial-conduct\", \"retaliation\", \"competency\", \"due-process\", \"communications\", \"repeat-actor\"]','2026-05-22 03:55:02','2026-05-22 03:55:02','public_preview','no_ai_processing',NULL,NULL,NULL,NULL,'state');
INSERT INTO `documents` (`id`, `title`, `description`, `file_key`, `file_url`, `mime_type`, `file_size`, `source_type`, `case_number`, `document_date`, `actor_names`, `issue_tags`, `story_id`, `public_status`, `review_status`, `redaction_status`, `uploaded_by`, `ai_summary`, `ai_tags`, `created_at`, `updated_at`, `visibility`, `ai_policy`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`, `case_tag`) VALUES (270002,'Demand for Immediate Settlement and Notice of Potential Federal Civil Rights and RICO Litigation (Church v. Washoe County DA)','This document is an email correspondence from Cameron Church, acting as counsel for Marilyn Denise Church, to the Washoe County District Attorney\'s Office and other parties. It serves as a demand for immediate settlement, alleging egregious violations of civil rights, elder abuse, exploitation, and RICO violations against Marilyn Denise Church. The email details specific alleged misconduct by the DA\'s office, Judge Barry L. Breslow, prosecutor Aziz Merchant, Reno Police Department, and Washoe County Sheriff’s Office, threatening federal litigation if a settlement is not reached by March 28, 2025. It includes a detailed breakdown of claimed damages and legal precedents.','evidence/ingest-240002-03-19-25_aziz_9061b647.pdf','/manus-storage/evidence/ingest-240002-03-19-25_aziz_9061b647.pdf','application/pdf',276712,'email',NULL,'2025-03-19 00:00:00','Cameron Church, Marilyn Church, Christopher J. Hicks, Kendall Holcomb, Aziz Merchant, Barry L. Breslow, Washoe County District Attorney\'s Office, Reno Police Department, Washoe County Sheriff’s Office, Nevada Attorney General’s Office, U.S. Department of Justice – Civil Rights Division, U.S. Attorney’s Office – District of Nevada','[\"civil-rights\", \"rico\", \"elder-abuse\", \"prosecutorial-conduct\", \"judicial-misconduct\", \"retaliation\", \"records-obstruction\", \"federal\", \"complaint\", \"demand-letter\"]',60001,1,'approved','unverified',1,'This document is an email correspondence from Cameron Church, acting as counsel for Marilyn Denise Church, to the Washoe County District Attorney\'s Office and other parties. It serves as a demand for immediate settlement, alleging egregious violations of civil rights, elder abuse, exploitation, and RICO violations against Marilyn Denise Church. The email details specific alleged misconduct by the DA\'s office, Judge Barry L. Breslow, prosecutor Aziz Merchant, Reno Police Department, and Washoe County Sheriff’s Office, threatening federal litigation if a settlement is not reached by March 28, 2025. It includes a detailed breakdown of claimed damages and legal precedents.','[\"civil-rights\", \"rico\", \"elder-abuse\", \"prosecutorial-conduct\", \"judicial-misconduct\", \"retaliation\", \"records-obstruction\", \"federal\", \"complaint\", \"demand-letter\"]','2026-05-22 03:55:24','2026-05-22 03:55:24','public_preview','no_ai_processing',NULL,NULL,NULL,NULL,'state');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (1,'faretta_self_representation','Faretta / Self-Representation Rights','Issues related to a defendant\'s Sixth Amendment right to self-representation, including denial of Faretta hearings, inadequate colloquy, or coerced waiver of counsel. Faretta v. California, 422 U.S. 806 (1975).','constitutional','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (2,'speedy_trial_delay','Speedy Trial / Delay','Violations of the Sixth Amendment right to a speedy trial, including unexplained continuances, strategic delays, or failure to bring a defendant to trial within statutory timeframes. Barker v. Wingo, 407 U.S. 514 (1972).','constitutional','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (3,'due_process_defect','Due Process Defect','Procedural or substantive due process violations under the Fifth or Fourteenth Amendment, including lack of notice, denial of opportunity to be heard, or fundamentally unfair proceedings.','constitutional','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (4,'brady_discovery_issue','Brady / Discovery Issue','Failure to disclose exculpatory or impeachment evidence as required by Brady v. Maryland, 373 U.S. 83 (1963), Giglio v. United States, 405 U.S. 150 (1972), or applicable state discovery rules.','discovery','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (5,'competency_proceeding_abuse','Competency Proceeding Abuse','Misuse of competency evaluation or restoration proceedings, including using competency as a delay tactic, failure to follow Drope/Pate standards, or improper commitment without adequate basis.','procedural','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (6,'retaliation_first_amendment','First Amendment Retaliation','Adverse government action taken in response to protected speech, petition, or association, including retaliatory prosecution, enhanced charges, or procedural retaliation for exercising legal rights.','civil_rights','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (7,'warrant_or_bail_defect','Warrant or Bail Defect','Defects in arrest warrants, search warrants, or bail determinations, including lack of probable cause, overbreadth, or excessive bail in violation of the Eighth Amendment.','constitutional','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (8,'record_integrity_issue','Record Integrity Issue','Concerns about the accuracy, completeness, or authenticity of the official court record, including missing transcripts, altered docket entries, or discrepancies between filed and recorded documents.','procedural','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (9,'nunc_pro_tunc_concern','Nunc Pro Tunc Concern','Retroactive court orders or entries used to alter the record in ways that affect substantive rights, particularly where the retroactive entry is not supported by the original record.','judicial_conduct','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (10,'prosecutorial_misconduct','Prosecutorial Misconduct','Improper conduct by a prosecutor including misrepresentation to the court, vouching for witnesses, improper argument, selective prosecution, or abuse of charging discretion.','prosecutorial_conduct','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (11,'judicial_disqualification_bias','Judicial Disqualification / Bias','Issues involving a judge\'s failure to recuse when required, appearance of partiality, ex parte communications, or conduct indicating bias against a party or class of litigants.','judicial_conduct','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (12,'access_to_courts_interference','Access to Courts Interference','Actions that obstruct a party\'s meaningful access to the courts, including denial of filing rights, interference with legal mail, restriction of self-represented litigant access, or retaliation for filing.','civil_rights','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (13,'fourth_amendment_search_seizure','Fourth Amendment / Search and Seizure','Unlawful searches, seizures, or surveillance without valid warrant or recognized exception, including fruit of the poisonous tree issues and suppression hearing defects.','constitutional','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (14,'elder_or_caregiver_impact','Elder or Caregiver Impact','Cases where the defendant or affected party is an elder, caregiver, or person with a dependent, and where prosecution or institutional action has disproportionate collateral impact on vulnerable third parties.','civil_rights','2026-05-18 04:42:29');
INSERT INTO `violation_tags` (`id`, `slug`, `label`, `description`, `category`, `created_at`) VALUES (15,'public_records_noncompliance','Public Records Noncompliance','Failure to comply with public records request obligations, including untimely responses, improper denials, withholding of non-exempt records, or failure to maintain required records.','public_records','2026-05-18 04:42:29');
