INSERT INTO `stories` (`id`, `submitter_name`, `alias`, `email`, `phone`, `case_number`, `court`, `department`, `judge`, `prosecutor`, `defense_attorney`, `charges`, `date_case_started`, `custody_days`, `still_pending`, `trial_held`, `requested_trial`, `counsel_waived_time`, `filings_blocked`, `asked_self_rep`, `faretta_handled`, `competency_raised`, `competency_context`, `discovery_missing`, `warrants_used`, `family_harm`, `summary`, `main_issue`, `public_permission`, `redaction_confirmed`, `status`, `reviewer_note`, `featured`, `slug`, `created_at`, `updated_at`, `owner_user_id`, `submitter_ip_hash`, `deleted_at`, `deleted_by`, `editorial_note`, `correction_note`) VALUES (60001,'Reno Record Editorial','Editorial','editor@therenorecord.org',NULL,'CR23-0657','Second Judicial District Court, Washoe County, Nevada — Department 8','Dept. ___','Barry L. Breslow','Aziz Merchant, Deputy District Attorney (Washoe County DA)','Galen Carrico (conflict counsel, appointed June 2024); Samuel Figueroa (2025); Joel Merchant (July 2025)','Grand Larceny of a Motor Vehicle (NRS 205.228); Unlawful Taking of a Motor Vehicle (added Aug 2023)','2023-03-12 00:00:00',1150,1,0,1,1,1,1,0,1,'Competency was raised after the defendant repeatedly demanded a speedy trial, requested self-representation, and filed pro se motions challenging counsel\'s waivers of time. The competency proceedings followed those assertions in close temporal proximity.',1,1,'Loss of caregiver income for dependents; family separation across multiple custody periods; missed employment cycles; documented mental-health and medical impact during pretrial detention.','The Church Record is the canonical case file documented by The Reno Record. The defendant repeatedly invoked a constitutional right to a speedy trial. Counsel of record waived statutory time without express on-record consent. Pro se filings — including motions to dismiss for speedy-trial violations and to permit self-representation — were filed, then either struck, ignored, or treated as legal nullities while counsel remained on record. Competency was raised after these assertions, not before. Pretrial detention extended past one year without trial, with collateral harm to dependents documented contemporaneously. This summary describes the issues on the public record; specific filings and orders are linked from the Evidence Archive as they are reviewed and approved for publication.','Speedy trial demanded for over a year while filings were blocked and competency was used to interrupt assertion of constitutional rights.',1,1,'approved',NULL,1,'the-church-record','2026-05-19 09:42:15','2026-05-20 23:54:50',NULL,NULL,NULL,NULL,NULL,NULL);
